#include <stdio.h>
#include <limits.h>

int maxDisp = INT_MIN;

void dfs(int node, int maxWealth, int *a, int **adj, int *visited, int n) {
    if (visited[node] == 1) return;
    visited[node] = 1;
    maxDisp = maxDisp > maxWealth - a[node] ? maxDisp : maxWealth - a[node];
    maxWealth = maxWealth > a[node] ? maxWealth : a[node];
    for (int i = 0; i < n; i++) {
        if (adj[node][i] == 1) {
            dfs(i, maxWealth, a, adj, visited, n);
        }
    }
}

int main() {
    int n;
    scanf("%d", &n);
    int *a = (int *)malloc(n * sizeof(int));
    int **adj = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        adj[i] = (int *)malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) {
            adj[i][j] = 0;
        }
    }
    int *p = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    for (int i = 0; i < n; i++) {
        scanf("%d", &p[i]);
        if (p[i] != -1) {
            adj[p[i] - 1][i] = 1;
        }
    }
    int *visited = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < n; i++) {
        if (p[i] == -1) {
            dfs(i, a[i], a, adj, visited, n);
        }
    }
    printf("%d\n", maxDisp);
    return 0;
}

