import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Main {
    static int maxDisp = Integer.MIN_VALUE;

    public static void dfs(int node, List<List<Integer>> adj, int[] a, int maxWealth) {
        maxDisp = Math.max(maxDisp, maxWealth - a[node]);
        maxWealth = Math.max(maxWealth, a[node]);
        for (int ne : adj.get(node)) {
            dfs(ne, adj, a, maxWealth);
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[] a = new int[n + 1];
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i <= n; i++) {
            adj.add(new ArrayList<>());
        }
        for (int i = 0; i < n; i++) {
            a[i + 1] = sc.nextInt();
        }
        int start = 0;
        for (int i = 1; i < n + 1; i++) {
            int q = sc.nextInt();
            if (q == -1) {
                start = i;
            } else {
                adj.get(q).add(i);
            }
        }
        dfs(start, adj, a, a[start]);
        System.out.println(maxDisp);
    }
}

